def validate(args, output):
    n = args[0]
    k = args[1]
    if not isinstance(output, list) or len(output) != n:
        return False
    if sorted(output) != list(range(1, n + 1)):
        return False
    diffs = set()
    for i in range(1, n):
        diffs.add(abs(output[i] - output[i - 1]))
    return len(diffs) == k

