function validate(args, output) {
    const n = args[0];
    const k = args[1];
    if (!Array.isArray(output) || output.length !== n) return false;
    const sorted = output.slice().sort((a, b) => a - b);
    for (let i = 0; i < n; i++) if (sorted[i] !== i + 1) return false;
    const diffs = new Set();
    for (let i = 1; i < n; i++) diffs.add(Math.abs(output[i] - output[i - 1]));
    return diffs.size === k;
}

