class Solution:
    def constructArray(self, n, k):
        res = [v for v in range(1, n - k)]
        nums = list(range(n - k, n + 1))
        left, right = 0, len(nums) - 1
        take_left = True
        while left <= right:
            if take_left:
                res.append(nums[left])
                left += 1
            else:
                res.append(nums[right])
                right -= 1
            take_left = not take_left
        return res

