class Solution:
    def constructArray(self, n, k):
        res = list(range(1, n - k))
        lo, hi = n - k, n
        flip = True
        while lo <= hi:
            if flip:
                res.append(lo)
                lo += 1
            else:
                res.append(hi)
                hi -= 1
            flip = not flip
        return res

