var constructArray = function(n, k) {
    const res = [];
    for (let v = 1; v < n - k; v++) res.push(v);
    let lo = n - k, hi = n;
    let flip = true;
    while (lo <= hi) {
        if (flip) { res.push(lo); lo++; }
        else { res.push(hi); hi--; }
        flip = !flip;
    }
    return res;
};
